begin;
create table public.one_passes(id uuid primary key default gen_random_uuid(),user_id uuid not null unique references auth.users(id) on delete cascade,status text not null default 'setup' check(status in('setup','ready','locked','deleted')),version integer not null default 1,identity_use_policy text not null default 'always_ask' check(identity_use_policy in('use_once_delete','always_ask','device_confirmation_every_time')),created_at timestamptz not null default now(),updated_at timestamptz not null default now(),deleted_at timestamptz);
create table public.travel_preferences(id uuid primary key default gen_random_uuid(),user_id uuid not null unique references auth.users(id) on delete cascade,departure_airports text[] not null default '{}',airlines text[] not null default '{}',hotel_brands text[] not null default '{}',seat_preference text,cabin_preference text,meal_preference text,room_preference text,bed_preference text,smoking_preference text,dietary_restrictions text[] not null default '{}',accessibility_requirements text[] not null default '{}',preferred_transport text[] not null default '{}',budget_preference text check(budget_preference in('lowest_price','maximum_points','best_balance','preferred_brands')),checkin_preferences jsonb not null default '{}',timezone text,travel_style text,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),check(pg_column_size(checkin_preferences)<=8192));
create table public.traveler_profiles(id uuid primary key default gen_random_uuid(),user_id uuid not null references auth.users(id) on delete cascade,display_name text not null check(char_length(display_name)<=80),traveler_type text not null default 'self' check(traveler_type in('self','adult_companion','minor_companion')),created_at timestamptz not null default now(),updated_at timestamptz not null default now(),deleted_at timestamptz);
create table public.identity_vault_records(id uuid primary key default gen_random_uuid(),user_id uuid not null references auth.users(id) on delete cascade,traveler_profile_id uuid references public.traveler_profiles(id) on delete cascade,ciphertext text not null,nonce text not null,algorithm text not null check(algorithm='AES-256-GCM'),key_version text not null,masked_passport_number text,passport_expiration_date date,status text not null default 'unverified' check(status in('unverified','verified','expired','replaced','revoked')),use_once_delete boolean not null default false,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),deleted_at timestamptz,unique(user_id,traveler_profile_id));
create table public.identity_verifications(id uuid primary key default gen_random_uuid(),user_id uuid not null references auth.users(id) on delete cascade,vault_record_id uuid not null references public.identity_vault_records(id) on delete cascade,provider text not null,provider_reference text,method text not null,status text not null check(status in('pending','verified','failed','expired','deleted')),verified_at timestamptz,expires_at timestamptz,created_at timestamptz not null default now());
create table public.loyalty_accounts(id uuid primary key default gen_random_uuid(),user_id uuid not null references auth.users(id) on delete cascade,provider text not null,program text not null,protected_membership_reference text not null,masked_membership_number text not null,member_name text,tier text,expires_at date,preferred_usage text check(preferred_usage in('lowest_total_price','maximum_points','best_balance','preferred_brands_first')),verification_status text not null default 'unverified' check(verification_status in('unverified','verified','expired')),created_at timestamptz not null default now(),updated_at timestamptz not null default now(),deleted_at timestamptz,unique(user_id,provider,program,protected_membership_reference));
create table public.payment_method_references(id uuid primary key default gen_random_uuid(),user_id uuid not null references auth.users(id) on delete cascade,provider text not null,provider_reference text not null,masked_label text not null,status text not null default 'pending' check(status in('pending','connected','disabled','revoked')),is_default boolean not null default false,supported_transaction_types text[] not null default '{}',last_verified_at timestamptz,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),revoked_at timestamptz,unique(user_id,provider,provider_reference));
create unique index one_default_payment_per_user on public.payment_method_references(user_id) where is_default and revoked_at is null;
create table public.passkey_credentials(id uuid primary key default gen_random_uuid(),user_id uuid not null references auth.users(id) on delete cascade,credential_id text not null unique,public_key text not null,algorithm integer not null,sign_count bigint not null default 0,transports text[] not null default '{}',device_name text not null check(char_length(device_name)<=80),created_at timestamptz not null default now(),last_used_at timestamptz,revoked_at timestamptz);
create table public.passkey_challenges(id uuid primary key default gen_random_uuid(),user_id uuid references auth.users(id) on delete cascade,challenge text not null unique,purpose text not null,action_hash text,expires_at timestamptz not null,consumed_at timestamptz,created_at timestamptz not null default now());
create table public.booking_intents(id uuid primary key default gen_random_uuid(),user_id uuid not null references auth.users(id) on delete cascade,mission_id uuid not null references public.missions(id) on delete cascade,status text not null default 'draft' check(status in('draft','price_recheck_required','ready_for_review','awaiting_user_approval','approved','executing','booking_confirmed','payment_confirmed','completed','rejected','expired','invalidated','price_changed','booking_failed','payment_failed','partially_completed','refund_required','refunded','cancelled')),provider text,provider_offer_reference text,price numeric(14,2),currency char(3),idempotency_key text not null,version integer not null default 1,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),expires_at timestamptz,unique(user_id,idempotency_key));
create table public.approval_packages(id uuid primary key default gen_random_uuid(),user_id uuid not null references auth.users(id) on delete cascade,mission_id uuid not null references public.missions(id) on delete cascade,booking_intent_id uuid references public.booking_intents(id) on delete cascade,version integer not null,payload_hash text not null check(payload_hash~'^[a-f0-9]{64}$'),protected_payload_reference text not null,summary jsonb not null,risk_level public.risk_level not null,status text not null default 'draft' check(status in('draft','price_recheck_required','ready_for_review','awaiting_user_approval','approved','executing','booking_confirmed','payment_confirmed','completed','rejected','expired','invalidated','price_changed','booking_failed','payment_failed','partially_completed','refund_required','refunded','cancelled')),expires_at timestamptz not null,approved_at timestamptz,consumed_at timestamptz,created_at timestamptz not null default now(),check(pg_column_size(summary)<=32768),unique(booking_intent_id,version));
create table public.provider_transactions(id uuid primary key default gen_random_uuid(),user_id uuid not null references auth.users(id) on delete cascade,booking_intent_id uuid not null references public.booking_intents(id) on delete cascade,provider text not null,transaction_type text not null,status text not null,provider_reference text,idempotency_key text not null,amount numeric(14,2),currency char(3),created_at timestamptz not null default now(),updated_at timestamptz not null default now(),unique(provider,idempotency_key));
create table public.booking_confirmations(id uuid primary key default gen_random_uuid(),user_id uuid not null references auth.users(id) on delete cascade,booking_intent_id uuid not null references public.booking_intents(id) on delete cascade,provider text not null,confirmation_reference text not null,masked_confirmation text not null,status text not null,confirmed_at timestamptz not null,created_at timestamptz not null default now(),unique(provider,confirmation_reference));
create table public.itinerary_items(id uuid primary key default gen_random_uuid(),user_id uuid not null references auth.users(id) on delete cascade,mission_id uuid not null references public.missions(id) on delete cascade,booking_confirmation_id uuid references public.booking_confirmations(id) on delete set null,item_type text not null,title text not null,start_at timestamptz,end_at timestamptz,timezone text,provider text,status text not null default 'prepared',safe_details jsonb not null default '{}',sequence integer not null,created_at timestamptz not null default now(),check(pg_column_size(safe_details)<=16384),unique(mission_id,sequence));
create table public.vault_access_events(id uuid primary key default gen_random_uuid(),user_id uuid not null references auth.users(id) on delete cascade,vault_record_id uuid not null references public.identity_vault_records(id) on delete cascade,approval_package_id uuid references public.approval_packages(id) on delete set null,purpose text not null,provider text,fields_used text[] not null default '{}',result text not null,correlation_id text,created_at timestamptz not null default now());

create index passkey_user_idx on public.passkey_credentials(user_id) where revoked_at is null;create index challenge_expiry_idx on public.passkey_challenges(expires_at) where consumed_at is null;create index booking_user_idx on public.booking_intents(user_id,created_at desc);create index package_user_status_idx on public.approval_packages(user_id,status,created_at desc);create index itinerary_user_mission_idx on public.itinerary_items(user_id,mission_id,sequence);create index vault_access_user_idx on public.vault_access_events(user_id,created_at desc);

alter table public.one_passes enable row level security;alter table public.travel_preferences enable row level security;alter table public.traveler_profiles enable row level security;alter table public.identity_vault_records enable row level security;alter table public.identity_verifications enable row level security;alter table public.loyalty_accounts enable row level security;alter table public.payment_method_references enable row level security;alter table public.passkey_credentials enable row level security;alter table public.passkey_challenges enable row level security;alter table public.booking_intents enable row level security;alter table public.approval_packages enable row level security;alter table public.provider_transactions enable row level security;alter table public.booking_confirmations enable row level security;alter table public.itinerary_items enable row level security;alter table public.vault_access_events enable row level security;
create policy owner_select_one_passes on public.one_passes for select using(user_id=auth.uid());create policy owner_select_travel_preferences on public.travel_preferences for select using(user_id=auth.uid());create policy owner_select_traveler_profiles on public.traveler_profiles for select using(user_id=auth.uid());create policy owner_select_identity_vault_records on public.identity_vault_records for select using(user_id=auth.uid());create policy owner_select_identity_verifications on public.identity_verifications for select using(user_id=auth.uid());create policy owner_select_loyalty_accounts on public.loyalty_accounts for select using(user_id=auth.uid());create policy owner_select_payment_method_references on public.payment_method_references for select using(user_id=auth.uid());create policy owner_select_passkey_credentials on public.passkey_credentials for select using(user_id=auth.uid());create policy owner_select_passkey_challenges on public.passkey_challenges for select using(user_id=auth.uid());create policy owner_select_booking_intents on public.booking_intents for select using(user_id=auth.uid());create policy owner_select_approval_packages on public.approval_packages for select using(user_id=auth.uid());create policy owner_select_provider_transactions on public.provider_transactions for select using(user_id=auth.uid());create policy owner_select_booking_confirmations on public.booking_confirmations for select using(user_id=auth.uid());create policy owner_select_itinerary_items on public.itinerary_items for select using(user_id=auth.uid());create policy owner_select_vault_access_events on public.vault_access_events for select using(user_id=auth.uid());
create policy owner_one_pass_write on public.one_passes for all using(user_id=auth.uid()) with check(user_id=auth.uid());
create policy owner_travel_write on public.travel_preferences for all using(user_id=auth.uid()) with check(user_id=auth.uid());
create policy owner_traveler_write on public.traveler_profiles for all using(user_id=auth.uid()) with check(user_id=auth.uid());
revoke insert,update,delete on public.identity_vault_records,public.identity_verifications,public.payment_method_references,public.passkey_credentials,public.passkey_challenges,public.booking_intents,public.approval_packages,public.provider_transactions,public.booking_confirmations,public.itinerary_items,public.vault_access_events from authenticated;
revoke select on public.identity_vault_records,public.identity_verifications,public.passkey_credentials,public.passkey_challenges,public.approval_packages,public.provider_transactions,public.vault_access_events from authenticated;
revoke insert,update,delete on public.loyalty_accounts from authenticated;
create trigger one_pass_updated before update on public.one_passes for each row execute function public.set_updated_at();create trigger travel_preferences_updated before update on public.travel_preferences for each row execute function public.set_updated_at();create trigger traveler_profiles_updated before update on public.traveler_profiles for each row execute function public.set_updated_at();create trigger vault_records_updated before update on public.identity_vault_records for each row execute function public.set_updated_at();create trigger loyalty_updated before update on public.loyalty_accounts for each row execute function public.set_updated_at();create trigger payment_references_updated before update on public.payment_method_references for each row execute function public.set_updated_at();create trigger booking_intents_updated before update on public.booking_intents for each row execute function public.set_updated_at();create trigger provider_transactions_updated before update on public.provider_transactions for each row execute function public.set_updated_at();
commit;
